// manifest.json - Complete OData configuration
{
  "sap.app": {
    "id": "com.company.salesorders",
    "dataSources": {
      "mainService": {
        "uri": "/sap/opu/odata/sap/ZSALES_SRV/",
        "type": "OData",
        "settings": {
          "odataVersion": "2.0",
          "localUri": "localService/metadata.xml"
        }
      }
    }
  },
  "sap.ui5": {
    "models": {
      "": {
        "dataSource": "mainService",
        "preload": true,
        "settings": { "useBatch": true }
      }
    }
  }
}

// Component.js - Framework auto-initializes model from manifest
sap.ui.define(["sap/ui/core/UIComponent"], function(UIComponent) {
  return UIComponent.extend("com.company.salesorders.Component", {
    metadata: { manifest: "json" }, // reads manifest.json
    init: function() {
      UIComponent.prototype.init.apply(this, arguments);
      // Model is ALREADY created by framework from manifest
      // No manual: new ODataModel(...) needed
      this.getRouter().initialize();
    }
  });
});

// In Controller - just access the pre-built model
onInit: function() {
  var oModel = this.getView().getModel(); // default model
  // Ready to use - metadata already loading
}

// Error handling pattern in controller
oModel.read("/SalesOrderSet", {
  filters: aFilters,
  success: function(oData) {
    oViewModel.setProperty("/orders", oData.results);
  },
  error: function(oError) {
    var sMessage = "Data load failed";
    try {
      var oErrObj = JSON.parse(oError.responseText);
      sMessage = oErrObj.error.message.value || sMessage;
    } catch(e) {
      // responseText not JSON, use default
    }
    sap.m.MessageBox.error(sMessage, {
      title: "Error"
    });
  }
});

// model.read with $expand
oModel.read("/SalesOrderSet('0000012345')", {
  urlParameters: {
    "$expand": "SalesOrderItems,SalesOrderPartners"
  },
  success: function(oData) {
    // oData.SalesOrderItems.results = array of items
    // oData.SalesOrderPartners.results = partners
  }
});

// XML binding with expand
<List items="{path: '/SalesOrderSet',
  parameters: {expand: 'SalesOrderItems'}}">
  <StandardListItem title="{SalesOrder}">
    <!-- Nested items binding -->
  </StandardListItem>
</List>

// Create operation in controller
onSavePress: function() {
  var oModel = this.getView().getModel();
  var oNewOrder = {
    CustomerID: "1001",
    NetAmount: "5000.00",
    Currency: "INR"
  };
  oModel.create("/SalesOrderSet", oNewOrder, {
    success: function(oData) {
      // oData.__metadata.uri has new entity URL
      var sNewKey = oData.SalesOrder; // backend-generated
      sap.m.MessageToast.show("Order " + sNewKey + " created");
      oModel.refresh(); // refresh list
    },
    error: function(oError) {
      sap.m.MessageBox.error("Create failed");
    }
  });
}

